32	    // Safe to iterate directly — mutations (add/remove) only happen in
33	    // setup/cleanup, not during dispatch. Set iteration is stable for
34	    // entries that existed when iteration began.
35	    handlers.forEach((handler) => {
36	      handler(event)
37	    })
38	  }
39	}
40	
41	/**
42	 * Register a handler for a document-level event type.
43	 * Returns an unsubscribe function.
44	 */
45	export function addDelegatedEventListener(eventType: string, handler: Handler): () => void {
46	  const set = getOrCreateSet(eventType)
47	  set.add(handler)
48	
49	  return () => {
50	    set.delete(handler)
51	    if (set.size === 0) {
52	      handlersByType.delete(eventType)
53	      document.removeEventListener(eventType, dispatch, usesCapturePhase(eventType))
54	    }
55	  }
56	}
57	
58	/**
59	 * Reset for testing purposes.
60	 */
61	export function resetEventDelegation(): void {
62	  handlersByType.forEach((_handlers, eventType) => {
63	    document.removeEventListener(eventType, dispatch, usesCapturePhase(eventType))
64	  })
65	  handlersByType.clear()
66	}
